}

solution_code:
#include <iostream>

int main()
{
    int a{};
    std::cin >> a;
    int* arr1{ new int[a]{} };
    for (int i{ 0 }; i < a; ++i)
        std::cin >> arr1[i];

    int b{};
    std::cin >> b;
    int* arr2{ new int[b]{} };
    for (int i{ 0 }; i < b; ++i)
        std::cin >> arr2[i];

    int* merged{ new int[a + b]{} };

    int i{ 0 };
    int j{ 0 };
    int k{ 0 };

    while (i < a && j < b)
    {
        if (arr1[i] <= arr2[j])
            merged[k++] = arr1[i++];
        else
            merged[k++] = arr2[j++];
    }

    while (i < a)
        merged[k++] = arr1[i++];

    while (j < b)
        merged[k++] = arr2[j++];

    for (int m{ 0 }; m < a + b; ++m)
        std::cout << merged[m] << ' ';

    delete[] arr1;
    delete[] arr2;
    delete[] merged;
    return 0;
}
